 73→#[cfg(target_os = "linux")]
 74→pub fn is_network_filesystem(path: &Path) -> bool {
 75→    crate::file_system::linux_mounts::is_network_filesystem_linux(path)
 76→}
 77→
 78→#[cfg(not(any(target_os = "macos", target_os = "linux")))]
 79→pub fn is_network_filesystem(_path: &Path) -> bool {
 80→    // On unsupported platforms, assume local filesystem
 81→    false
 82→}
 83→
 84→// ============================================================================
 85→// Chunked copy with metadata
 86→// ============================================================================
 87→
 88→/// Copies a file using chunked read/write with cancellation checks.
 89→///
 90→/// This is used for network filesystems where `copyfile()` doesn't respond
 91→/// to cancellation in a timely manner. The copy checks for cancellation
 92→/// between each 1MB chunk, allowing near-instant response to cancel requests.
 93→///
 94→/// After the data copy, all metadata is preserved:
 95→/// - Extended attributes (includes macOS resource forks, Finder info)
 96→/// - ACLs (access control lists)
 97→/// - Timestamps (modification time, access time)
 98→/// - Permissions
 99→///
100→/// The optional progress callback is called after each chunk with
101→/// (bytes_copied_so_far, total_bytes).
102→pub fn chunked_copy_with_metadata(
103→    source: &Path,
104→    dest: &Path,
105→    cancelled: &Arc<AtomicBool>,
106→    progress_callback: Option<ChunkedCopyProgressFn>,
107→) -> Result<u64, WriteOperationError> {
108→    log::info!(
109→        "chunked_copy: starting chunked copy from {} to {}",
110→        source.display(),
111→        dest.display()
112→    );
113→
114→    // Get source size for progress reporting
115→    let source_size = std::fs::metadata(source).map(|m| m.len()).unwrap_or(0);
116→
117→    // 1. Chunked data copy with cancellation checks
118→    let bytes = copy_data_chunked(source, dest, cancelled, source_size, progress_callback)?;
119→
120→    // 2. Copy all metadata (best effort - log warnings but don't fail)
121→    if let Err(e) = copy_metadata(source, dest) {
122→        log::warn!(
123→            "chunked_copy: failed to copy some metadata from {} to {}: {:?}",
124→            source.display(),
125→            dest.display(),
126→            e
127→        );
128→    }
129→
130→    log::info!(
131→        "chunked_copy: completed {} bytes from {} to {}",
132→        bytes,
133→        source.display(),
134→        dest.display()
135→    );
136→
137→    Ok(bytes)
138→}
139→
140→/// Copies file data in chunks, checking cancellation between each chunk.
141→fn copy_data_chunked(
142→    source: &Path,
143→    dest: &Path,
144→    cancelled: &Arc<AtomicBool>,
145→    source_size: u64,
146→    progress_callback: Option<ChunkedCopyProgressFn>,
147→) -> Result<u64, WriteOperationError> {
148→    let mut src_file = std::fs::File::open(source).map_err(|e| WriteOperationError::IoError {
149→        path: source.display().to_string(),
150→        message: format!("Failed to open source file: {}", e),
151→    })?;
152→
153→    let mut dst_file = std::fs::File::create(dest).map_err(|e| WriteOperationError::IoError {
154→        path: dest.display().to_string(),
155→        message: format!("Failed to create destination file: {}", e),
156→    })?;
157→
158→    let mut buffer = vec![0u8; CHUNK_SIZE];
159→    let mut total_bytes = 0u64;
160→
161→    loop {
162→        // Check cancellation BEFORE each read
163→        if cancelled.load(Ordering::Relaxed) {
164→            log::info!(
165→                "chunked_copy: cancellation detected after {} bytes, cleaning up",
166→                total_bytes
167→            );
168→            // Clean up partial file
169→            drop(dst_file);
170→            let _ = std::fs::remove_file(dest);
171→            return Err(WriteOperationError::Cancelled {
172→                message: "Operation cancelled by user".to_string(),
173→            });
174→        }
175→
176→        let bytes_read = src_file.read(&mut buffer).map_err(|e| WriteOperationError::IoError {
177→            path: source.display().to_string(),
178→            message: format!("Failed to read from source: {}", e),
179→        })?;
180→
181→        if bytes_read == 0 {
182→            break; // EOF
183→        }
184→
185→        dst_file
186→            .write_all(&buffer[..bytes_read])
187→            .map_err(|e| WriteOperationError::IoError {
188→                path: dest.display().to_string(),
189→                message: format!("Failed to write to destination: {}", e),
190→            })?;
191→
192→        total_bytes += bytes_read as u64;
193→
194→        // Report progress after each chunk
195→        if let Some(cb) = progress_callback {
196→            cb(total_bytes, source_size);
197→        }
198→    }
199→
200→    // Note: sync_all() removed - network writes are synchronous and the async sync
201→    // at operation completion handles durability. Blocking sync defeats cancellation.
202→
203→    Ok(total_bytes)
204→}
205→
206→// ============================================================================
207→// Metadata copying
208→// ============================================================================
209→
210→/// Copies all metadata from source to destination.
211→fn copy_metadata(source: &Path, dest: &Path) -> Result<(), WriteOperationError> {
212→    // 1. Copy extended attributes (includes resource forks, Finder info)
213→    copy_xattrs(source, dest)?;
214→
215→    // 2. Copy ACLs
216→    copy_acls(source, dest)?;
217→
218→    // 3. Copy timestamps
219→    copy_timestamps(source, dest)?;
220→
221→    // 4. Copy permissions
222→    copy_permissions(source, dest)?;
223→
224→    Ok(())
225→}
226→
227→/// Copies extended attributes from source to destination.
228→fn copy_xattrs(source: &Path, dest: &Path) -> Result<(), WriteOperationError> {
229→    // List all xattrs on source
230→    let xattrs = match xattr::list(source) {
231→        Ok(iter) => iter.collect::<Vec<_>>(),
232→        Err(e) => {
233→            log::debug!("copy_xattrs: failed to list xattrs on {}: {}", source.display(), e);
234→            return Ok(()); // Not all filesystems support xattrs
235→        }
236→    };
237→
238→    for attr_name in xattrs {
239→        // Get the attribute value from source
240→        let value = match xattr::get(source, &attr_name) {
241→            Ok(Some(v)) => v,
242→            Ok(None) => continue, // Attribute disappeared
243→            Err(e) => {
244→                log::debug!(
245→                    "copy_xattrs: failed to get xattr {:?} from {}: {}",
246→                    attr_name,
247→                    source.display(),
248→                    e
249→                );
250→                continue;
251→            }
252→        };
253→
254→        // Set the attribute on destination
255→        if let Err(e) = xattr::set(dest, &attr_name, &value) {
256→            log::debug!(
257→                "copy_xattrs: failed to set xattr {:?} on {}: {}",
258→                attr_name,
259→                dest.display(),
260→                e
261→            );
262→            // Continue with other xattrs
263→        }
264→    }
265→
266→    Ok(())
267→}
268→
269→/// Copies ACLs (access control lists) from source to destination.
270→#[cfg(any(target_os = "macos", target_os = "linux", target_os = "freebsd"))]
271→fn copy_acls(source: &Path, dest: &Path) -> Result<(), WriteOperationError> {
272→    use exacl::{AclOption, getfacl, setfacl};
273→
274→    // Get ACL from source (best effort - not all filesystems support ACLs)
275→    let acl = match getfacl(source, AclOption::empty()) {
276→        Ok(acl) => acl,
277→        Err(e) => {
278→            log::debug!("copy_acls: failed to get ACL from {}: {}", source.display(), e);
279→            return Ok(());
280→        }
281→    };
282→
283→    // Set ACL on destination
284→    if let Err(e) = setfacl(&[dest], &acl, AclOption::empty()) {
285→        log::debug!("copy_acls: failed to set ACL on {}: {}", dest.display(), e);
286→    }
287→
288→    Ok(())
289→}
290→
291→#[cfg(not(any(target_os = "macos", target_os = "linux", target_os = "freebsd")))]
292→fn copy_acls(_source: &Path, _dest: &Path) -> Result<(), WriteOperationError> {
293→    // ACLs not supported on this platform
294→    Ok(())
295→}
296→
297→/// Copies timestamps (mtime, atime) from source to destination.
298→fn copy_timestamps(source: &Path, dest: &Path) -> Result<(), WriteOperationError> {
299→    let metadata = std::fs::metadata(source).map_err(|e| WriteOperationError::IoError {
300→        path: source.display().to_string(),
301→        message: format!("Failed to read source metadata: {}", e),
302→    })?;
303→
304→    let mtime = filetime::FileTime::from_last_modification_time(&metadata);
305→    let atime = filetime::FileTime::from_last_access_time(&metadata);
306→
307→    filetime::set_file_times(dest, atime, mtime).map_err(|e| WriteOperationError::IoError {
308→        path: dest.display().to_string(),
309→        message: format!("Failed to set timestamps: {}", e),
310→    })?;
311→
312→    Ok(())
313→}
314→
315→/// Copies permissions from source to destination.
316→fn copy_permissions(source: &Path, dest: &Path) -> Result<(), WriteOperationError> {
317→    let metadata = std::fs::metadata(source).map_err(|e| WriteOperationError::IoError {
318→        path: source.display().to_string(),
319→        message: format!("Failed to read source metadata: {}", e),
320→    })?;
321→
322→    std::fs::set_permissions(dest, metadata.permissions()).map_err(|e| WriteOperationError::IoError {
323→        path: dest.display().to_string(),
324→        message: format!("Failed to set permissions: {}", e),
325→    })?;
326→
327→    Ok(())
328→}
329→
330→// ============================================================================
331→// Tests
332→// ============================================================================
333→
334→#[cfg(test)]
335→mod tests {
336→    use super::*;
337→    use std::fs;
338→
339→    fn create_temp_dir(name: &str) -> std::path::PathBuf {
340→        let temp_dir = std::env::temp_dir().join(format!("cmdr_chunked_copy_test_{}", name));
341→        let _ = fs::remove_dir_all(&temp_dir);
342→        fs::create_dir_all(&temp_dir).expect("Failed to create temp directory");
343→        temp_dir
344→    }
345→
346→    fn cleanup_temp_dir(path: &std::path::PathBuf) {
347→        let _ = fs::remove_dir_all(path);
348→    }
349→
350→    #[test]
351→    fn test_is_network_filesystem_local() {
352→        // Local paths should return false
353→        assert!(!is_network_filesystem(Path::new("/")));
354→        assert!(!is_network_filesystem(Path::new("/tmp")));
355→        assert!(!is_network_filesystem(Path::new("/Users")));
356→    }
357→
358→    #[test]
359→    fn test_is_network_filesystem_nonexistent() {
360→        // Non-existent paths should check parent
361→        assert!(!is_network_filesystem(Path::new("/tmp/nonexistent_file_12345")));
362→    }
363→
364→    #[test]
365→    fn test_chunked_copy_basic() {
366→        let temp_dir = create_temp_dir("basic");
367→        let src = temp_dir.join("source.txt");
368→        let dst = temp_dir.join("dest.txt");
369→
370→        fs::write(&src, "Hello, chunked copy!").unwrap();
371→
372→        let cancelled = Arc::new(AtomicBool::new(false));
373→        let result = chunked_copy_with_metadata(&src, &dst, &cancelled, None);
374→
375→        assert!(result.is_ok());
376→        assert_eq!(result.unwrap(), 20); // "Hello, chunked copy!" is 20 bytes
377→        assert!(dst.exists());
378→        assert_eq!(fs::read_to_string(&dst).unwrap(), "Hello, chunked copy!");
379→
380→        cleanup_temp_dir(&temp_dir);
381→    }
382→
383→    #[test]
384→    fn test_chunked_copy_cancellation() {
385→        let temp_dir = create_temp_dir("cancel");
386→        let src = temp_dir.join("source.txt");
387→        let dst = temp_dir.join("dest.txt");
388→
389→        // Create a file larger than CHUNK_SIZE to ensure we hit the cancellation check
390→        let large_content = "x".repeat(CHUNK_SIZE + 1000);
391→        fs::write(&src, &large_content).unwrap();
392→
393→        // Pre-cancelled
394→        let cancelled = Arc::new(AtomicBool::new(true));
395→        let result = chunked_copy_with_metadata(&src, &dst, &cancelled, None);
396→
397→        assert!(matches!(result, Err(WriteOperationError::Cancelled { .. })));
398→        // Partial file should be cleaned up
399→        assert!(!dst.exists());
400→
401→        cleanup_temp_dir(&temp_dir);
402→    }
403→
404→    #[test]
405→    fn test_chunked_copy_preserves_permissions() {
406→        use std::os::unix::fs::PermissionsExt;
407→
408→        let temp_dir = create_temp_dir("perms");
409→        let src = temp_dir.join("source.sh");
410→        let dst = temp_dir.join("dest.sh");
411→
412→        fs::write(&src, "#!/bin/bash").unwrap();
413→        fs::set_permissions(&src, fs::Permissions::from_mode(0o755)).unwrap();
414→
415→        let cancelled = Arc::new(AtomicBool::new(false));
416→        let result = chunked_copy_with_metadata(&src, &dst, &cancelled, None);
417→
418→        assert!(result.is_ok());
419→        let dst_perms = fs::metadata(&dst).unwrap().permissions().mode();
420→        assert_eq!(dst_perms & 0o777, 0o755);
421→
422→        cleanup_temp_dir(&temp_dir);
423→    }
424→
425→    #[test]
426→    fn test_chunked_copy_empty_file() {
427→        let temp_dir = create_temp_dir("empty");
428→        let src = temp_dir.join("empty.txt");
429→        let dst = temp_dir.join("dest.txt");
430→
431→        fs::write(&src, "").unwrap();
432→
433→        let cancelled = Arc::new(AtomicBool::new(false));
434→        let result = chunked_copy_with_metadata(&src, &dst, &cancelled, None);
435→
436→        assert!(result.is_ok());
437→        assert_eq!(result.unwrap(), 0);
438→        assert!(dst.exists());
439→        assert_eq!(fs::read_to_string(&dst).unwrap(), "");
440→
441→        cleanup_temp_dir(&temp_dir);
442→    }
443→
444→    #[test]
445→    fn test_chunked_copy_progress_callback() {
446→        use std::sync::atomic::AtomicU64;
447→
448→        let temp_dir = create_temp_dir("progress");
449→        let src = temp_dir.join("source.txt");
450→        let dst = temp_dir.join("dest.txt");
451→
452→        // Create a file larger than CHUNK_SIZE to ensure multiple callbacks
453→        let large_content = "x".repeat(CHUNK_SIZE * 2 + 1000);
454→        let expected_size = large_content.len() as u64;
455→        fs::write(&src, &large_content).unwrap();
456→
457→        let cancelled = Arc::new(AtomicBool::new(false));
458→        let callback_count = Arc::new(AtomicU64::new(0));
459→        let last_bytes = Arc::new(AtomicU64::new(0));
460→
461→        let callback_count_clone = Arc::clone(&callback_count);
462→        let last_bytes_clone = Arc::clone(&last_bytes);
463→        let progress_cb = move |bytes_done: u64, total: u64| {
464→            callback_count_clone.fetch_add(1, Ordering::Relaxed);
465→            last_bytes_clone.store(bytes_done, Ordering::Relaxed);
466→            assert_eq!(total, expected_size);
467→        };
468→
469→        let result = chunked_copy_with_metadata(&src, &dst, &cancelled, Some(&progress_cb));
470→
471→        assert!(result.is_ok());
472→        assert_eq!(result.unwrap(), expected_size);
473→        // Should have been called at least 3 times (for 3 chunks)
474→        assert!(callback_count.load(Ordering::Relaxed) >= 3);
475→        // Last callback should report all bytes
476→        assert_eq!(last_bytes.load(Ordering::Relaxed), expected_size);
477→
478→        cleanup_temp_dir(&temp_dir);
479→    }
480→}
