306→/// Copies a single file or symlink to its destination.
307→/// Ensures parent directories exist before copying.
308→/// Used by both copy and cross-filesystem move operations.
309→#[allow(
310→    clippy::too_many_arguments,
311→    reason = "File copy requires passing state through multiple levels"
312→)]
313→pub(super) fn copy_single_item(
314→    source: &Path,
315→    dest_path: PathBuf,
316→    is_symlink: bool,
317→    files_done: &mut usize,
318→    bytes_done: &mut u64,
319→    files_total: usize,
320→    bytes_total: u64,
321→    state: &Arc<WriteOperationState>,
322→    app: &tauri::AppHandle,
323→    operation_id: &str,
324→    operation_type: WriteOperationType,
325→    progress_interval: &Duration,
326→    last_progress_time: &mut Instant,
327→    config: &WriteOperationConfig,
328→    transaction: &mut CopyTransaction,
329→    apply_to_all_resolution: &mut Option<ConflictResolution>,
330→    created_dirs: &mut HashSet<PathBuf>,
331→) -> Result<(), WriteOperationError> {
332→    use tauri::Emitter;
333→
334→    // Check cancellation
335→    if state.cancelled.load(Ordering::Relaxed) {
336→        log::debug!(
337→            "copy: cancellation detected op={} files_done={}",
338→            operation_id,
339→            *files_done
340→        );
341→        return Err(WriteOperationError::Cancelled {
342→            message: "Operation cancelled by user".to_string(),
343→        });
344→    }
345→
346→    // Ensure parent directories exist
347→    if let Some(parent) = dest_path.parent()
348→        && !created_dirs.contains(parent)
349→        && !parent.exists()
350→    {
351→        // Collect directories that don't exist BEFORE creating them
352→        // (so we know exactly which ones we're creating for rollback)
353→        let mut dirs_to_create: Vec<PathBuf> = Vec::new();
354→        let mut dir = parent.to_path_buf();
355→        while !dir.exists() && !created_dirs.contains(&dir) {
356→            dirs_to_create.push(dir.clone());
357→            match dir.parent() {
358→                Some(p) => dir = p.to_path_buf(),
359→                None => break,
360→            }
361→        }
362→
363→        // Create all directories
364→        fs::create_dir_all(parent).map_err(|e| WriteOperationError::IoError {
365→            path: parent.display().to_string(),
366→            message: format!("Failed to create directory: {}", e),
367→        })?;
368→
369→        // Record only the directories we actually created (in creation order: deepest last)
370→        // dirs_to_create is in reverse order (deepest first), so iterate in reverse
371→        for created_dir in dirs_to_create.into_iter().rev() {
372→            transaction.record_dir(created_dir.clone());
373→            created_dirs.insert(created_dir);
374→        }
375→    }
376→
377→    // Get metadata for size tracking
378→    let metadata = fs::symlink_metadata(source).with_path(source)?;
379→
380→    let file_name = source.file_name().unwrap_or_default();
381→
382→    if is_symlink {
383→        // Handle symlink
384→        let (actual_dest, needs_safe_overwrite) = if dest_path.exists() || fs::symlink_metadata(&dest_path).is_ok() {
385→            match resolve_conflict(
386→                source,
387→                &dest_path,
388→                config,
389→                app,
390→                operation_id,
391→                state,
392→                apply_to_all_resolution,
393→            )? {
394→                Some(resolved) => (resolved.path, resolved.needs_safe_overwrite),
395→                None => {
396→                    // Skip this file but still count it toward progress
397→                    *files_done += 1;
398→                    *bytes_done += metadata.len();
399→                    return Ok(());
400→                }
401→            }
402→        } else {
403→            (dest_path.clone(), false)
