183→/// Starts a move operation in the background.
184→///
185→/// Uses instant rename() for same-filesystem moves.
186→/// Uses atomic staging pattern for cross-filesystem moves.
187→pub async fn move_files_start(
188→    app: tauri::AppHandle,
189→    sources: Vec<PathBuf>,
190→    destination: PathBuf,
191→    config: WriteOperationConfig,
192→) -> Result<WriteOperationStartResult, WriteOperationError> {
193→    validate_sources(&sources)?;
194→    validate_destination(&destination)?;
195→    validate_destination_writable(&destination)?;
196→    validate_not_same_location(&sources, &destination)?;
197→    validate_destination_not_inside_source(&sources, &destination)?;
198→
199→    log::info!(
200→        "move_files_start: sources={:?}, destination={:?}, dry_run={}",
201→        sources,
202→        destination,
203→        config.dry_run
204→    );
205→
206→    start_write_operation(
207→        app,
208→        WriteOperationType::Move,
209→        config.progress_interval_ms,
210→        move |app, op_id, state| move_files_with_progress(&app, &op_id, &state, &sources, &destination, &config),
211→    )
212→    .await
213→}
214→
215→/// Starts a delete operation in the background.
216→///
217→/// Recursively deletes files and directories. When `volume_id` is provided and
218→/// is not the default volume, routes through `delete_volume_files_with_progress`
219→/// which uses the Volume trait (needed for MTP and other non-local volumes).
220→pub async fn delete_files_start(
221→    app: tauri::AppHandle,
222→    sources: Vec<PathBuf>,
223→    config: WriteOperationConfig,
224→    volume_id: Option<String>,
225→) -> Result<WriteOperationStartResult, WriteOperationError> {
226→    let volume_id_str = volume_id.unwrap_or_else(|| "root".to_string());
227→    let volume = if volume_id_str != "root" {
228→        Some(
229→            crate::file_system::get_volume_manager()
230→                .get(&volume_id_str)
231→                .ok_or_else(|| WriteOperationError::IoError {
232→                    path: volume_id_str.clone(),
233→                    message: format!("Volume '{}' not found", volume_id_str),
234→                })?,
235→        )
236→    } else {
237→        validate_sources(&sources)?;
238→        None
239→    };
240→
241→    log::info!(
242→        "delete_files_start: sources={:?}, volume={}, dry_run={}",
243→        sources,
244→        volume_id_str,
245→        config.dry_run
246→    );
247→
248→    start_write_operation(
249→        app,
250→        WriteOperationType::Delete,
251→        config.progress_interval_ms,
252→        move |app, op_id, state| {
253→            if let Some(vol) = volume {
254→                delete_volume_files_with_progress(vol, &app, &op_id, &state, &sources, &config)
255→            } else {
256→                delete_files_with_progress(&app, &op_id, &state, &sources, &config)
257→            }
258→        },
259→    )
260→    .await
261→}
